var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 재건 도시 <color=#ffd34c>ARC-NL1</color>\\n구 네덜란드, 암스테르담","JPN":"管理局再建都市<color=#ffd34c>ARC-NL1</color>\\n旧オランダ、アムステルダム","ENG":"[[","TWN":"管理局重建城市<color=#ffd34c>ARC-NL1</color>\\n舊荷蘭 阿姆斯特丹","SCN":"管理局重建城市<color=#ffd34c>ARC-NL1</color>\\n旧荷兰，阿姆斯特丹","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"다국적 합자 대침식 연구소 – 퓨처 앳 워\\n<color=#ffd34c>제3지부 트레이닝 룸</color>","JPN":"多国籍合資対侵食戦研究所 - フューチャーアットウォー\\n<color=#ffd34c>第3支部トレーニングルーム</color>","ENG":"[[","TWN":"跨國合資反侵蝕研究所-天啟兵器\\n<color=#ffd34c>第三分部訓練室</color>","SCN":"跨国合资反侵蚀研究所-天启兵器\\n<color=#ffd34c>第三分部训练室</color>","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……그럼, 라이카가 원래 맨션 소속이었다는 말이에요?","JPN":"……じゃあ、ライカはもともとマンションの所属だったの？","ENG":"...So, you're saying Laika used to be with the Mansion?","TWN":"……那麼，萊卡原本是屬於曼森的嗎？"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"야, 꼬맹이. 말은 똑바로 해.","JPN":"おい、おこちゃま。違うだろうが。","ENG":"Hey, kid. Get your facts straight.","TWN":"喂，小鬼。說話要注意點。"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"빌어먹을 조국은 우주 탐사를 위해, 꼬맹이였던 우리를 맨션에 파견 보냈어.","JPN":"クソ祖国は宇宙探査のために、ガキだった私たちをマンションに派遣した。","ENG":"My stupid homeland sent us, just a bunch of kids, to the Mansion in the name of space exploration.","TWN":"該死的國家為了宇宙探險，把我們這些小孩送到曼森裡。"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"당시 맨션은 평범한 인간을 훈련과 시술로 카운터처럼 만들 수 있다고 알려져 있었거든.","JPN":"当時マンションは普通の人間を訓練と施術でカウンターのように作り上げることで有名だったからな。","ENG":"Back then, the Mansion was known for turning regular humans into Counter-like fighters through training and procedures.","TWN":"當時據說曼森可以通過訓練和手術將普通人變成制裁者。"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"평범한 사람을 카운터처럼 만든다고요? 그게 가능해요?","JPN":"普通の人間をカウンターに作り上げる？　それって可能なの？","ENG":"Turning regular people into Counter-like ones? Is that even possible?","TWN":"把普通人變成制裁者？這可能嗎？"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"바보야. 가능할 리가 있겠냐?","JPN":"バカ、可能なわけないだろ？","ENG":"Don't be stupid. Of course not.","TWN":"笨蛋。怎麼可能呢？"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그게 성공했다면, 지금처럼 태스크포스가 일부러 비싼 카운터를 영입할 필요가 없잖아.","JPN":"それができたら、今みたいにタスクフォースがわざわざ高額でカウンターを雇う必要なんてない。","ENG":"If it worked, TASKFORCEs wouldn't be wasting money recruiting real Counters.","TWN":"如果真的成功了，特遣勢力哪還需要像現在這樣雇傭昂貴的制裁者？"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"마스터의 특수한 약물로 카운터처럼 될 수는 있지만, 약효는 어디까지나 일시적이야.","JPN":"マスターの特殊な薬物でカウンターみたいにはなれるけど、薬の効果はあくまでも一時的だ。","ENG":"You can mimic a Counter for a while with Master's special drug, but the effect is temporary.","TWN":"雖然可以通過主人的特殊藥物變得像制裁者一樣，但藥效終究只是暫時的。"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"하지만 단 한 사람…….","JPN":"たった1人……","ENG":"Except for one person...","TWN":"但只有一個人……"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"<color=#ffd34c>베로니카</color>라는 이름 붙여진 메이드는 달랐지만.","JPN":"<color=#ffd34c>ベロニカ</color>って名前のメイドは違ったけどな。","ENG":"A maid named <color=#ffd34c>Veronica</color> was different.","TWN":"一個叫<color=#ffd34c>貝洛妮卡</color>的女僕，只有她與眾不同。"},"stage":{"bg":"SS_MAID_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"무슨 수를 쓴 건지는 모르겠지만, 카운터인 메이드들조차 그 여자한테는 상대가 안 됐어.","JPN":"どんな手を使ったのか知らないけど、カウンターのメイドですらその女には歯が立たなかった。","ENG":"I don't know what they did to her, but even Counter maids couldn't touch her.","TWN":"雖然不知道她用了什麼手段，連制裁者女僕們都不是她的對手。"},"stage":{"bg":"SS_MAID_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"할망구 말로는 맨션의 역대 메이드장 중에서 정점이었다나, 뭐라나……?","JPN":"ババァの話によると、マンションの歴代メイド長の中でもトップだったとか……？","ENG":"The hag claimed she was the greatest Chief Maid in Mansion's history or whatever...","TWN":"瘋婆子說她是歷代曼森女僕長中的巔峰？"},"stage":{"bg":"SS_MAID_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아, 몰라! 메이드 따위 이제 내 알 바 아니라고!","JPN":"ああ、もう！　メイドなんか私の知ったことじゃない！","ENG":"Ugh, whatever! I couldn't care less about maids anymore!","TWN":"隨便啦！女僕現在與我無關了！"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아무튼 내 소속은 북방합의체 우주 탐사 대원이야! 맨션이 아니라……!","JPN":"とにかく、私の所属は北方合意体の宇宙探査隊員！　マンションじゃなく……！","ENG":"I'm a space explorer from the Northern Union! Not some Mansion flunky...!","TWN":"總之，我是北方和議會的宇宙探險隊員！不是曼森！"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"제가 보기엔 어차피 거기서 거기인 것 같은데요……?","JPN":"私から見たら、似たようなものだけど……？","ENG":"From where I'm standing, it's all the same...","TWN":"我覺得反正都差不多吧？"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"눈사람 놈들이나, 메이드들이나… 어차피 둘 다 나쁜 놈들이잖아요.","JPN":"スノーマンの奴らも、メイドも……悪いやつらには変わりないでしょう。","ENG":"Snowmen or maids... they're both just bad guys.","TWN":"雪人也好，女僕也好……反正都是壞傢伙嘛。"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"달라! 적어도 합의체 녀석들은 쪽팔리는 메이드복 입고 싸우라고 강요는 안 해……!","JPN":"違う！　少なくとも合意体のやつらはくそ恥ずかしいメイド服で戦えなんて言わない……！","ENG":"No, they're not! At least the Northern Union never forced us to wear skimpy maid outfits into battle...!","TWN":"不一樣！至少聯盟的那些傢伙不會強迫我們穿著丟臉的女僕裝去戰鬥！"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그 변태들이랑은 다르다고……!","JPN":"あの変態たちとは違うんだって……！","ENG":"Unlike those perverts...!","TWN":"和那些變態不一樣！"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"변태라니… 그러는 라이카도 유니폼 안쪽에, 몸에 딱 붙는 레오타드 입고 있으면서…….","JPN":"変態って……ライカだってユニフォームの下にぴったりフィットするレオタードを着ているくせに……","ENG":"Perverts? Says the one wearing a skin-tight leotard under her uniform...","TWN":"變態……但你自己不也是在制服裡面穿著緊身連身衣嗎？？"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"엇? 잠깐, 그럼 라이카도 메이드복을 입은 적 있어요?","JPN":"あっ？　とういことは、ライカもメイド服を着たことがあるの？","ENG":"Huh? Hold on a sec. Then have you also worn a maid outfit too?","TWN":"咦？等等，那萊卡也穿過女僕裝嗎？"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"……시끄러워, 꼬맹이.","JPN":"……うるさい、おこちゃま。","ENG":"...Shut it, kid.","TWN":"……閉嘴，小鬼。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};